import java.util.Queue;
import java.util.LinkedList;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

class Solution {
public:
    void inorder(Node root, int level, int minLevel, int maxLevel) {
        if (root == null) return;
        inorder(root.right, level + 1, minLevel, maxLevel);

        // Find the top view nodes
        if (level == minLevel) {
            // Create a new node with the minimum value
            Node newNode = new Node(root.value);
            // Update the minLevel and maxLevel
            maxLevel = level;
            minLevel = level + 1;
        }

        inorder(root.left, level + 1, minLevel, maxLevel);
    }

    Node removeTopView(Node root) {
        if (root == null) return null;

        inorder(root, 0, 0, 0);

        // Remove the top view node
        Node temp = root;
        while (temp != null) {
            if (temp.value == root.value) {
                if (temp.left == null) {
                    temp = temp.right;
                } else if (temp.right == null) {
                    temp = temp.left;
                } else {
                    // Find the minimum value node in the right subtree
                    Node minNode = temp.right;
                    while (minNode.left != null) {
                        minNode = minNode.left;
                    }
                    temp.value = minNode.value;
                    temp.right = minNode.right;
                }
                break;
            }
            temp = temp.left;
        }
        return root;
    }

    void printTree(Node root) {
        if (root == null) return;
        printTree(root.right);
        System.out.print(root.value + " ");
        printTree(root.left);
    }

    void traverse(Node root) {
        inorder(root, 0, 0, 0);
        System.out.println();
        printTree(root);
    }

    public static void main(String[] args) {
        Solution obj = new Solution();
        Node root = new Node(1);
        root.left = new Node(2);
        root.right = new Node(3);
        root.left.left = new Node(4);
        root.left.right = new Node(5);

        Node removed = obj.removeTopView(root);

        System.out.println("Removed Top View Node = " + removed.value);

        obj.traverse(root);
    }
}

