    removeTopView(node, level, minLevel, maxLevel) {
        if (node === null) return;
        this.removeTopView(node.right, level + 1, minLevel, maxLevel);

        // Find the top view nodes
        if (level == minLevel) {
            // Create a new node with the minimum value
            let newNode = new Node(node.value);
            // Update the minLevel and maxLevel
            maxLevel = level;
            minLevel = level + 1;
        }
        this.removeTopView(node.left, level + 1, minLevel, maxLevel);
    }

    remove(node, value) {
        if (node === null) return null;
        this.remove(node.left, value);
        if (node.value == value) {
            if (node.left === null) {
                return node.right;
            } else if (node.right === null) {
                return node.left;
            } else {
                // Find the minimum value node in the right subtree
                let minNode = node.right;
                while (minNode.left !== null) {
                    minNode = minNode.left;
                }
                node.value = minNode.value;
                node.right = minNode.right;
            }
            return node;
        }
